mapper.select:
SELECT FROM pm_lease l INNER JOIN property p ON p.id = l.property_id INNER JOIN tower tw ON tw.id = l.tower_id INNER JOIN unit_master u ON u.id = l.unit_id INNER JOIN customer c ON c.id = l.customer_id WHERE l.is_deleted = FALSE
AND ( LOWER(l.lease_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(l.lease_status) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND l.lease_status = #{leaseStatus}
AND l.renewal_status = #{renewalStatus}
ORDER BY l.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM pm_lease l INNER JOIN property p ON p.id = l.property_id INNER JOIN unit_master u ON u.id = l.unit_id INNER JOIN customer c ON c.id = l.customer_id WHERE l.is_deleted = FALSE
AND ( LOWER(l.lease_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(l.lease_status) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND l.lease_status = #{leaseStatus}
AND l.renewal_status = #{renewalStatus}

SELECT COUNT(*)
FROM pm_lease
WHERE unit_id = #{unitId}
  AND is_deleted = FALSE
  AND lease_status = 'ACTIVE'
  AND id != #{excludeId}
  AND start_date <= #{endDate}
  AND end_date >= #{startDate}

